#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N*sizeof(int));
        int maxVal = N+1;
        int *freq = (int*)calloc(maxVal+1, sizeof(int));
        for(int i=0;i<N;i++){
            scanf("%d", &a[i]);
            freq[a[i]]++;
        }
        int remaining = N;
        int mexPtr = 0;
        int *ans = (int*)malloc(N*sizeof(int));
        int ansLen = 0;
        while(remaining>0){
            while(mexPtr<=maxVal && freq[mexPtr]>0) mexPtr++;
            int mex = mexPtr;
            ans[ansLen++] = mex;
            if(mex>0){
                for(int v=0; v<mex; ++v){
                    freq[v]--; remaining--;
                }
            }else{ // mex == 0
                // delete any element, choose the smallest present
                int v=0; while(v<=maxVal && freq[v]==0) v++;
                freq[v]--; remaining--;
            }
        }
        printf("%d\n", ansLen);
        for(int i=0;i<ansLen;i++){
            if(i) printf(" ");
            printf("%d", ans[i]);
        }
        printf("\n");
        free(a); free(freq); free(ans);
    }
    return 0;
}

