#include <bits/stdc++.h>
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> freq(N+2,0);
        for(int i=0;i<N;++i){
            int x; cin>>x; ++freq[x];
        }
        int remaining=N;
        int mexPtr=0;
        vector<int> ans;
        ans.reserve(N);
        while(remaining>0){
            while(mexPtr<=N+1 && freq[mexPtr]>0) ++mexPtr;
            int mex=mexPtr;
            ans.push_back(mex);
            if(mex>0){
                for(int v=0; v<mex; ++v){
                    --freq[v]; --remaining;
                }
            }else{ // mex == 0
                int v=0; while(v<=N+1 && freq[v]==0) ++v;
                --freq[v]; --remaining;
            }
        }
        cout<<ans.size()<<'\n';
        for(size_t i=0;i<ans.size();++i){
            if(i) cout<<' ';
            cout<<ans[i];
        }
        cout<<'\n';
    }
    return 0;
}

