import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] freq = new int[N + 2];
            for (int i = 0; i < N; i++) {
                int x = fs.nextInt();
                freq[x]++;
            }
            int remaining = N;
            int mexPtr = 0;
            int[] ans = new int[N];
            int ansLen = 0;
            while (remaining > 0) {
                while (mexPtr <= N + 1 && freq[mexPtr] > 0) mexPtr++;
                int mex = mexPtr;
                ans[ansLen++] = mex;
                if (mex > 0) {
                    for (int v = 0; v < mex; v++) {
                        freq[v]--;
                        remaining--;
                    }
                } else {
                    int v = 0;
                    while (v <= N + 1 && freq[v] == 0) v++;
                    freq[v]--;
                    remaining--;
                }
            }
            out.append(ansLen).append('\n');
            for (int i = 0; i < ansLen; i++) {
                if (i > 0) out.append(' ');
                out.append(ans[i]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }

    // Fast scanner for competitive programming
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

