    freq[x]++;
  }
  let remaining = N;
  let mexPtr = 0;
  const ans = [];
  while (remaining > 0) {
    while (mexPtr <= N + 1 && freq[mexPtr] > 0) mexPtr++;
    const mex = mexPtr;
    ans.push(mex);
    if (mex > 0) {
