        freq[v]--;
        remaining--;
      }
    } else {
      let v = 0;
      while (v <= N + 1 && freq[v] === 0) v++;
      freq[v]--;
      remaining--;
    }
  }
  output.push(String(ans.length));
  output.push(ans.join(' '));
